// // This module implements a PNG compression filter called 'Add' filter, which adds the value of the pixel to the left to the current pixel.
module png_sub_filter (
    input [7:0] current_pixel,
    input [7:0] previous_pixel,
    output [7:0] filtered_pixel
);
    assign filtered_pixel = current_pixel - previous_pixel;
endmodule
